%% create_mlfcn_model.m
% Creates enginespeed_qat_mlfcn.slx — a Windows/platform-portable version
% of enginespeed_qat_sfun.slx using a MATLAB Function block (no MEX needed).
% The QAT LSTM-32 weights are embedded directly in the MATLAB function code.

clc;
PROJ = '/Users/arkadiyturevskiy/Documents/Claude/Claude_ROM_session4';
cd(PROJ);
addpath(fullfile(PROJ, 'src'));

src_mdl  = 'enginespeed_qat_sfun';
new_mdl  = 'enginespeed_qat_mlfcn';
src_file = fullfile(PROJ, [src_mdl '.slx']);
new_file = fullfile(PROJ, [new_mdl '.slx']);
assert(isfile(src_file), 'Source model not found: %s', src_file);

warning('off','all');
if bdIsLoaded(src_mdl), close_system(src_mdl,0); end
if bdIsLoaded(new_mdl), close_system(new_mdl,0); end

%% Load source model and save as new name
load_system(src_file);
save_system(src_mdl, new_file);
close_system(src_mdl, 0);
load_system(new_file);

%% Find the S-Function block
all_blks = find_system(new_mdl, 'SearchDepth', 1, 'Type', 'block');
sfun_path = '';
for k = 1:numel(all_blks)
    bt = get_param(all_blks{k}, 'BlockType');
    if strcmp(bt, 'S-Function')
        sfun_path = all_blks{k};
        break;
    end
end
assert(~isempty(sfun_path), 'S-Function block not found');
fprintf('Found S-Function: %s\n', sfun_path);

sfun_pos = get_param(sfun_path, 'Position');
sfun_ph  = get_param(sfun_path, 'PortHandles');

% Capture connected blocks/ports before deleting
% Input: what drives the S-Function input (= Mux output)
in_line   = get_param(sfun_ph.Inport(1), 'Line');
in_src_ph = get_param(in_line, 'SrcPortHandle');

% Output: what the S-Function output drives
out_line   = get_param(sfun_ph.Outport(1), 'Line');
out_dst_ph = get_param(out_line, 'DstPortHandle');

% Delete old S-Function and its lines
delete_line(in_line);
delete_line(out_line);
delete_block(sfun_path);

%% Add MATLAB Function block
mlfcn_path = [new_mdl '/QAT ROM ML'];
add_block('simulink/User-Defined Functions/MATLAB Function', mlfcn_path, ...
    'Position', sfun_pos, 'BackgroundColor', 'cyan');

%% Set the MATLAB function code via Stateflow API
ml_code = build_qat_lstm_matlab_code();

% Access the embedded chart via Stateflow API
rt = sfroot();
model_obj = rt.find('-isa', 'Simulink.BlockDiagram', 'Name', new_mdl);
chart = model_obj.find('-isa', 'Stateflow.EMChart');
% If multiple, find by path
if numel(chart) > 1
    for kc = 1:numel(chart)
        if contains(chart(kc).Path, 'QAT ROM ML')
            chart = chart(kc);
            break;
        end
    end
end
assert(~isempty(chart), 'Could not find Stateflow EMChart for MATLAB Function block');
fprintf('Found EMChart: %s\n', chart.Path);

chart.Script = ml_code;

%% Update diagram to resolve ports
% Wrap in try-catch: the update may warn about missing workspace variables
% (sa_ts, throttle_ts) which are only needed at sim-time, not build-time.
try
    set_param(new_mdl, 'SimulationCommand', 'update');
    pause(2);
catch ME_upd
    fprintf('Note: model update warning (non-fatal): %s\n', ME_upd.message);
    pause(1);
end

%% Re-wire connections
mlfcn_ph = get_param(mlfcn_path, 'PortHandles');
add_line(new_mdl, in_src_ph, mlfcn_ph.Inport(1), 'autorouting', 'on');
add_line(new_mdl, mlfcn_ph.Outport(1), out_dst_ph, 'autorouting', 'on');

%% Signal logging on output port
set_param(mlfcn_ph.Outport(1), 'DataLogging', 'on');
set_param(mlfcn_ph.Outport(1), 'DataLoggingNameMode', 'Custom');
set_param(mlfcn_ph.Outport(1), 'DataLoggingName', 'Torque');

%% Model configuration
set_param(new_mdl, 'SignalLogging', 'on', 'SignalLoggingName', 'logsout');

%% Save
save_system(new_mdl, new_file);
close_system(new_mdl, 0);
fprintf('\nCreated: %s\n', new_file);
warning('on','all');

